ศรษฐศาสตร์ === */\n.bm-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.bm-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.bm-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.bm-cta-super-d{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.1;pointer-events:none;z-index:0}\n\n.bm-cta-container{position:relative;z-index:3;max-width:800px;margin:0 auto;text-align:center}\n.bm-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.bm-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.9);margin:0 0 40px;max-width:600px;margin-left:auto;margin-right:auto}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .bm-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .bm-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .bm-cta-container p{padding-bottom:0 !important}\n\n.bm-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.bm-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.bm-cta-btn:hover::before{left:100%}\n.bm-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.bm-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.bm-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.bm-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.bm-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.bm-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .bm-cta-title{font-size:28px;margin-bottom:16px}\n  .bm-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .bm-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .bm-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.bm-cta-btn{transition:none !important}.bm-cta-btn::before{display:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: วิกฤตโมเดลธุรกิจ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: วิกฤตโมเดลธุรกิจ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: วิกฤตโมเดลธุรกิจ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="bm-hero-section">\n      <div class="bm-hero-d-bg" aria-hidden="true"></div>\n      <div class="bm-hero-dot-overlay" aria-hidden="true"></div>\n      <div class="bm-hero-inner">\n        <div class="bm-hero-breadcrumb">\n          <a href="/partner-program/">โปรแกรมพันธมิตร</a>\n          <span>/</span>\n          <span>วิกฤตโมเดลธุรกิจ</span>\n        </div>\n        <h1 class="bm-hero-title">ปัญหาไม่ใช่ทีมของคุณ — แต่เป็นโมเดลธุรกิจ</h1>\n        <p class="bm-hero-subtitle">คุณเบื่อกับ Monday Morning Escalation และดูที่ปรึกษาอาวุโสทำหน้าที่เป็นพี่เลี้ยงกรอกข้อมูล กับดัก Man-Day กำลังจำกัดการเติบโตของคุณ คุณส่งมอบความสามารถระดับ Tier-1 ในราคา Tier-3 หน้านี้จะตั้งชื่อปัญหา — เพื่อให้คุณหลุดพ้นได้</p>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pattern: The Cycle Trap"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pattern: The Cycle Trap: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pattern: The Cycle Trap: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pat-section">\n      <div class="pat-inner">\n        <div class="pat-header">\n          <h2 class="pat-title">คุณรู้จักรูปแบบนี้</h2>\n          <p class="pat-subtitle">ทุก SI ใช้ชีวิตในวงจรเดียวกัน รู้สึกเหมือนมีประสิทธิภาพ แต่จริงๆ มันคือกับดัก</p>\n        </div>\n        <div class="pat-cycle">\n        <div class="pat-step">\n          <div class="pat-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg></div>\n          <h3>ชนะโปรเจกต์</h3>\n          <p>หลังจากหลายสัปดาห์ของ Proposal, Demo, และการเจรจา ในที่สุดคุณก็ได้ลูกค้า</p>\n        </div>\n        <div class="pat-step">\n          <div class="pat-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg></div>\n          <h3>ส่งมอบความเชี่ยวชาญ</h3>\n          <p>ทีมของคุณทำงานได้ยอดเยี่ยม แก้ปัญหายากๆ ทำให้ลูกค้าประสบความสำเร็จ</p>\n        </div>\n        <div class="pat-step">\n          <div class="pat-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg></div>\n          <h3>โปรเจกต์จบ</h3>\n          <p>ถ่ายทอดความรู้แล้ว ทีมลูกค้าจัดการได้เอง พวกเขาไม่ต้องการคุณอีกแล้ว</p>\n        </div>\n        <div class="pat-step">\n          <div class="pat-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 2.13-9.36L1 10"/></svg></div>\n          <h3>เริ่มจากศูนย์</h3>\n          <p>กลับไปล่าลูกค้าใหม่ Proposal ใหม่ เจรจาใหม่ วงจรเดิมซ้ำอีกครั้ง</p>\n        </div>\n        </div>\n        <div class="pat-repeat">\n          <p>และวงจรก็ซ้ำ… ไม่มีวันจบ <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="23 4 23 10 17 10"/><polyline points="1 20 1 14 7 14"/><path d="M3.51 9a9 9 0 0 1 14.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0 0 20.49 15"/></svg></p>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Evidence: Row 1 (The Math)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Evidence: Row 1 (The Math): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Evidence: Row 1 (The Math): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="math-section math-section--row1">\n      <div class="math-scene"><div id="dw-bm-scene"></div><script>(function(){var s=atob(\'\');document.getElementById(\'dw-bm-scene\').innerHTML=decodeURIComponent(Array.from(s,function(c){return \'%\'+(\'00\'+c.charCodeAt(0).toString(16)).slice(-2)}).join(\'\'));})()</script></div>\n      <div class="math-wave-fade" aria-hidden="true"></div>\n      <div class="math-inner">\n        <div class="math-header">\n          <h2 class="math-title">หลักฐานจากอุตสาหกรรม</h2>\n          <p class="math-subtitle">นี่ไม่ใช่เรื่องเล่า นี่คือตัวเลขที่บันทึกไว้ว่าทำไมโมเดลนี้ถึงพัง</p>\n        </div>\n        <div class="math-cards">\n          <div class="math-card">\n            <div class="math-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M3 3v18h18"/><path d="M18 17V9"/><path d="M13 17V5"/><path d="M8 17v-3"/></svg></div>\n            <h3>มาร์จินถูกบีบ</h3>\n            <p>มาร์จินสุทธิของโปรเจกต์หดตัวจาก ~35% ในปี 2018 เหลือ ~18% ในปี 2024 ลูกค้าต้องการความสามารถ Tier-1 ในราคา Tier-3 โปรเจกต์ 9 เดือนที่เคยกำไร ฿500k ตอนนี้ได้แค่ ~฿150k</p>\n            <div class="math-formula">\n              <code>ความพยายามเท่าเดิม = ผลตอบแทนครึ่งเดียว</code>\n            </div>\n          </div>\n          <div class="math-card">\n            <div class="math-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="8.5" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg></div>\n            <h3>เพดาน 35 คน</h3>\n            <p>บริษัทที่ปรึกษาขนาดเล็กไม่สามารถขยายเกิน 35-45 คน เพราะการส่งมอบพึ่งพา "ฮีโร่" อาวุโส จะเพิ่มรายได้ต้องจ้างเพิ่ม — เพิ่มค่าใช้จ่ายและความเสี่ยงโดยไม่มี Leverage</p>\n            <div class="math-formula">\n              <code>รายได้ = จำนวนคน (เพิ่มแบบเส้นตรงเท่านั้น)</code>\n            </div>\n          </div>\n          <div class="math-card">\n            <div class="math-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg></div>\n            <h3>ค่าทดแทน ฿200K</h3>\n            <p>การทดแทนที่ปรึกษาอาวุโสมีค่าใช้จ่าย ฿200,000 ในการสรรหา บวก 6 เดือนของการสูญเสียผลิตภาพ อาวุโสคนหนึ่งลาออกอาจทำให้ไม่สามารถรับงานใหม่ได้</p>\n            <div class="math-formula">\n              <code>สูญเสียคนเก่ง = 200K + 6 เดือน</code>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Evidence: Row 2 (More Math)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Evidence: Row 2 (More Math): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Evidence: Row 2 (More Math): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="math-section math-section--row2">\n      <div class="math-inner">\n        <div class="math-cards">\n          <div class="math-card">\n            <div class="math-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg></div>\n            <h3>กับดัก Overrun 65%</h3>\n            <p>65% ของงบประมาณเกินมาจากการแก้ไขระบบเพื่อปรับปรุง Usability กลายเป็น "งานน้ำใจที่เรียกเก็บไม่ได้" — แก้ไขซอฟต์แวร์ที่ไม่ยืดหยุ่นให้เข้ากับกระบวนการโรงงานไทย กินมาร์จินโดยตรง</p>\n            <div class="math-formula">\n              <code>แก้ไขด้วยน้ำใจ = กำไรหายไป</code>\n            </div>\n          </div>\n          <div class="math-card">\n            <div class="math-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><line x1="12" y1="20" x2="12" y2="10"/><line x1="18" y1="20" x2="18" y2="4"/><line x1="6" y1="20" x2="6" y2="16"/></svg></div>\n            <h3>ตัดราคา 30%</h3>\n            <p>โอเพนซอร์สและคู่แข่งท้องถิ่น (ERP ฟรี, ซอฟต์แวร์บัญชีไทย) เสนอค่า Implementation ถูกกว่า ~30% ไม่มีอาวุธที่แตกต่าง คุณถูกบังคับให้แข่งด้านราคา — วิ่งเข้าสู่ก้นเหว</p>\n            <div class="math-formula">\n              <code>สงครามราคา = มาร์จินตาย</code>\n            </div>\n          </div>\n          <div class="math-card">\n            <div class="math-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/></svg></div>\n            <h3>เค้กที่หดตัว</h3>\n            <p>ปัญหาเศรษฐกิจทำให้โรงงานปิด ~100 แห่ง/เดือน ในต้นปี 2024 ตลาดรวมที่หดตัวขณะที่การแข่งขันเพื่อลูกค้าที่แข็งแรงเข้มข้นขึ้น</p>\n            <div class="math-formula">\n              <code>โรงงานน้อยลง = แข่งมากขึ้น</code>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Futures: Three Paths"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Futures: Three Paths: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Futures: Three Paths: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="futures-section">\n      <div class="futures-wave-vertical" aria-hidden="true"></div>\n      <div class="futures-inner">\n        <div class="futures-header">\n          <h2 class="futures-title">สามอนาคตที่เป็นไปได้</h2>\n          <p class="futures-subtitle">คุณมีสามทางเลือก มีเพียงทางเดียวที่นำไปสู่การเติบโตอย่างยั่งยืน</p>\n        </div>\n        <div class="futures-paths">\n        <div class="futures-path futures-path--red" style="background:linear-gradient(135deg,#fef2f2,#fff5f5);border-color:#fecaca">\n          <div class="futures-path-top">\n            <div class="futures-path-icon" style="background:linear-gradient(135deg,#dc2626,#b91c1c)"><svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#fff" stroke-width="2" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></div>\n            <div>\n              <h3 style="color:#7f1d1d">ทางที่ 1: "ทำงานหนักขึ้น"</h3>\n              <p class="futures-path-subtitle" style="color:#991b1b">ทำไมไม่ได้ผล: คุณไม่สามารถเอาชนะมาร์จินที่ถูกบีบเชิงโครงสร้างด้วยการทำงานหนักขึ้น</p>\n            </div>\n          </div>\n          <p class="futures-path-body" style="color:#991b1b">ที่ปรึกษาอาวุโสใช้ 50% ของเวลาเป็น "พี่เลี้ยงกรอกข้อมูล" แทนที่จะเรียกเก็บค่าสถาปัตยกรรมมูลค่าสูง ความพยายามเท่าเดิมได้กำไรครึ่งเดียว ทำงานหนักขึ้นบนโมเดลเดิม = วิ่งเร็วขึ้นบนลู่วิ่งอยู่กับที่</p>\n        </div>\n        <div class="futures-path futures-path--yellow" style="background:linear-gradient(135deg,#fef9c3,#fefce8);border-color:#fde047">\n          <div class="futures-path-top">\n            <div class="futures-path-icon" style="background:linear-gradient(135deg,#eab308,#ca8a04)"><svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#fff" stroke-width="2" aria-hidden="true"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg></div>\n            <div>\n              <h3 style="color:#713f12">ทางที่ 2: "หา Niche"</h3>\n              <p class="futures-path-subtitle" style="color:#854d0e">ทำไมมีข้อจำกัด: คุณติดเพดานขนาดลูกค้าและความสามารถทางเทคนิค</p>\n            </div>\n          </div>\n          <p class="futures-path-body" style="color:#854d0e">ซอฟต์แวร์เฉพาะทางมักขาดการเชื่อมต่อ Industry 4.0 การทำ Niche หมายถึงต้องเขียน Custom Code จำนวนมาก — สร้าง "กุญแจมือทอง" ที่คนเก่งของคุณต้องดูแลโค้ดเก่า แทนที่จะ Deploy โปรเจกต์ใหม่</p>\n        </div>\n        <div class="futures-path futures-path--green" style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);border-color:#86efac">\n          <div class="futures-path-top">\n            <div class="futures-path-icon" style="background:linear-gradient(135deg,#22c55e,#16a34a)"><svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#fff" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg></div>\n            <div>\n              <h3 style="color:#166534">ทางที่ 3: "เปลี่ยนโมเดล"</h3>\n              <p class="futures-path-subtitle" style="color:#15803d">ทำไมสมเหตุสมผล: มันแยกรายได้ออกจากชั่วโมงการทำงาน</p>\n            </div>\n          </div>\n          <p class="futures-path-body" style="color:#15803d">ใช้ประโยชน์จากแพลตฟอร์ม PaaS เพื่อสร้าง Industry Template ที่ใช้ซ้ำได้ เปลี่ยน Customization ครั้งเดียวเป็น IP ที่สามารถขายลิขสิทธิ์ได้ เข้าลูกค้าผ่าน "Reverse Cut" ที่เสี่ยงต่ำ (MES/AIoT ก่อน) แล้วขยาย บริษัท 35 คนสร้างรายได้เท่าบริษัท 50 คน ผ่าน Technology Arbitrage</p>\n        </div>\n        </div>\n        <div class="futures-insight">\n          <div class="futures-insight-inner">\n            <p class="futures-insight-quote">"เปลี่ยนจากขายชั่วโมงเป็นสร้างสินทรัพย์ จาก Labor Arbitrage เป็น Technology Arbitrage"</p>\n            <p class="futures-insight-subtext">เป้าหมายไม่ใช่ขายซอฟต์แวร์มากขึ้น — แต่หยุดพึ่งพาค่าธรรมเนียมครั้งเดียวที่คาดเดาไม่ได้ และสร้างธุรกิจ "Farming" ที่ยั่งยืนจากรายได้บำรุงรักษาต่อเนื่องและ Module เสริม</p>\n          </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solution: Another Way"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solution: Another Way: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solution: Another Way: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sol-section">\n      <div class="sol-inner">\n        <div class="sol-header">\n          <h2 class="sol-title">มีทางออกอีกทาง</h2>\n          <p class="sol-subtitle">เพิ่มสายผลิตภัณฑ์ให้ธุรกิจบริการของคุณ และเปลี่ยนเศรษฐศาสตร์พื้นฐาน</p>\n        </div>\n        <div class="sol-cards">\n        <div class="sol-card">\n          <div class="sol-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg></div>\n          <h3>รายได้ต่อเนื่อง</h3>\n          <p>ลิขสิทธิ์ซอฟต์แวร์และค่าบำรุงรักษาสร้างรายได้รายเดือนที่คาดการณ์ได้ นอนหลับตอนลาพักร้อนได้ รายได้ยังคงไหลเข้ามา</p>\n          <div class="sol-formula">\n            <code>รายได้รายเดือน = ฐานลิขสิทธิ์ × อัตรา</code>\n          </div>\n        </div>\n        <div class="sol-card">\n          <div class="sol-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg></div>\n          <h3>ความสัมพันธ์ที่ยั่งยืน</h3>\n          <p>เมื่อลูกค้าใช้ซอฟต์แวร์ของคุณบริหารโรงงาน พวกเขาจะไม่ย้ายไปไหน คุณกลายเป็นโครงสร้างพื้นฐานสำคัญ ไม่ใช่ผู้ค้าที่ถูกเปลี่ยนได้</p>\n          <div class="sol-formula">\n            <code>อัตราการเปลี่ยนใจ → เกือบศูนย์</code>\n          </div>\n        </div>\n        <div class="sol-card">\n          <div class="sol-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg></div>\n          <h3>การเติบโตแบบทบต้น</h3>\n          <p>ปีที่ 2 = ลูกค้าปีที่ 1 + ลูกค้าใหม่ ทุกดีลเพิ่มฐานของคุณ ในที่สุดตัวเลขก็ทำงานในทิศทางที่เป็นประโยชน์ต่อคุณ</p>\n          <div class="sol-formula">\n            <code>ปีที่ N = ปีที่ N-1 + ลูกค้าใหม่</code>\n          </div>\n        </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Comparison: Side-by-Side"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Comparison: Side-by-Side: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Comparison: Side-by-Side: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cmp-section" data-particles>\n      <div class="cmp-d-bg" aria-hidden="true"></div>\n      <div class="cmp-inner">\n        <div class="cmp-header">\n          <h2 class="cmp-title">เปรียบเทียบแบบเคียงข้าง</h2>\n        </div>\n        <table class="cmp-table">\n          <caption class="sr-only">เปรียบเทียบโมเดลบริการอย่างเดียว กับ บริการ + ผลิตภัณฑ์</caption>\n          <thead>\n            <tr>\n              <th scope="col">ตัวชี้วัด</th>\n              <th scope="col">บริการอย่างเดียว</th>\n              <th scope="col">บริการ + ผลิตภัณฑ์</th>\n            </tr>\n          </thead>\n          <tbody>\n              <tr>\n                <td>โมเดลรายได้</td>\n                <td class="bad" data-label="บริการอย่างเดียว">รีเซ็ตเป็นศูนย์ทุกปี</td>\n                <td class="good" data-label="บริการ + ผลิตภัณฑ์">เติบโตแบบทบต้นทุกปี</td>\n              </tr>\n              <tr>\n                <td>ความสัมพันธ์ลูกค้า</td>\n                <td class="bad" data-label="บริการอย่างเดียว">ตามโปรเจกต์ จบแล้วจบกัน</td>\n                <td class="good" data-label="บริการ + ผลิตภัณฑ์">ต่อเนื่อง ถาวร</td>\n              </tr>\n              <tr>\n                <td>ความสม่ำเสมอของรายได้</td>\n                <td class="bad" data-label="บริการอย่างเดียว">ฟีสต์หรืออดอยาก</td>\n                <td class="good" data-label="บริการ + ผลิตภัณฑ์">มีฐานที่คาดการณ์ได้ + การเติบโต</td>\n              </tr>\n              <tr>\n                <td>มูลค่าธุรกิจ</td>\n                <td class="bad" data-label="บริการอย่างเดียว">1-2x รายได้ (ถ้ามี)</td>\n                <td class="good" data-label="บริการ + ผลิตภัณฑ์">5-10x รายได้ต่อเนื่อง</td>\n              </tr>\n              <tr>\n                <td>การพึ่งพาเจ้าของ</td>\n                <td class="bad" data-label="บริการอย่างเดียว">ธุรกิจ = ตัวคุณ</td>\n                <td class="good" data-label="บริการ + ผลิตภัณฑ์">ธุรกิจ = ฐานลูกค้า</td>\n              </tr>\n              <tr>\n                <td>เพดานการเติบโต</td>\n                <td class="bad" data-label="บริการอย่างเดียว">จำกัดโดยจำนวนคน</td>\n                <td class="good" data-label="บริการ + ผลิตภัณฑ์">จำกัดโดยขนาดตลาด</td>\n              </tr>\n          </tbody>\n        </table>\n      </div>\n    </div>\n    <script>/**\n * DigiWin 数据洋流 (Data Ocean Current)\n *\n * Recreates the brand kit\'s signature visual: a 3D dot-grid surface\n * with dramatic rolling wave crests, viewed from a low angle.\n * Reference: DigiWin 2025 Annual Report cover, brand kit pp.61-68.\n *\n * Usage:\n *   <section data-particles>              — subtle on light bg (default)\n *   <section data-particles="bold">       — vivid on dark navy bg\n *   <section data-particles="medium">     — moderate visibility\n *\n * WordPress: wp_enqueue_script or Code Module. Self-initializing.\n */\n\n(function () {\n    \'use strict\';\n\n    var reducedMotion = window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n    var PI2 = Math.PI * 2;\n\n    // ── Brand colors (RGB) ──────────────────────────────────────────\n    var BLUE = [0, 175, 240];   // #00AFF0 Smart Blue\n    var CYAN = [0, 230, 255];   // #00E6FF Cyan accent\n\n    // ── Presets ─────────────────────────────────────────────────────\n    var PRESETS = {\n        light: {\n            frontOpacity: 0.18,   // visible but not distracting on white/light backgrounds\n            backOpacity: 0.03,\n            frontRadius: 3.5,\n            backRadius: 0.5,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.10\n        },\n        subtle: {\n            frontOpacity: 0.30,   // foreground dot opacity\n            backOpacity: 0.04,    // distant dot opacity\n            frontRadius: 4.5,     // foreground dot size (px)\n            backRadius: 0.6,      // distant dot size (px)\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.12\n        },\n        medium: {\n            frontOpacity: 0.45,\n            backOpacity: 0.06,\n            frontRadius: 5.0,\n            backRadius: 0.8,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.18\n        },\n        bold: {\n            frontOpacity: 0.60,\n            backOpacity: 0.10,\n            frontRadius: 5.5,\n            backRadius: 1.0,\n            color: CYAN,\n            colorAlt: BLUE,\n            altRatio: 0.25\n        }\n    };\n\n    // ── Utility ─────────────────────────────────────────────────────\n    function lerp(a, b, t) { return a + (b - a) * t; }\n\n    // ── DataOcean class ─────────────────────────────────────────────\n    function DataOcean(el) {\n        this.el = el;\n        this.canvas = null;\n        this.ctx = null;\n        this.w = 0;\n        this.h = 0;\n        this.dpr = Math.min(window.devicePixelRatio || 1, 2);\n        this.visible = false;\n        this.raf = null;\n        this.time = 0;\n        this.resizeTimer = null;\n        this.colors = null; // pre-assigned per grid point\n\n        this.opts = this._parseOpts();\n        this._setup();\n        this._buildColors();\n        this._observe();\n\n        if (!reducedMotion) {\n            this._loop();\n        } else {\n            this.visible = true;\n            this._draw(0);\n        }\n    }\n\n    DataOcean.prototype._parseOpts = function () {\n        var name = this.el.getAttribute(\'data-particles\') || \'subtle\';\n        if (name === \'\' || name === \'true\') name = \'subtle\';\n        return PRESETS[name] || PRESETS.subtle;\n    };\n\n    DataOcean.prototype._setup = function () {\n        var c = document.createElement(\'canvas\');\n        c.setAttribute(\'aria-hidden\', \'true\');\n        c.style.cssText = \'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n        var pos = getComputedStyle(this.el).position;\n        if (pos === \'static\') this.el.style.position = \'relative\';\n        this.el.style.overflow = \'hidden\';\n        this.el.insertBefore(c, this.el.firstChild);\n        this.canvas = c;\n        this.ctx = c.getContext(\'2d\');\n        this._resize();\n\n        var self = this;\n        window.addEventListener(\'resize\', function () {\n            clearTimeout(self.resizeTimer);\n            self.resizeTimer = setTimeout(function () {\n                self._resize();\n                self._buildColors();\n            }, 200);\n        });\n    };\n\n    DataOcean.prototype._resize = function () {\n        var r = this.el.getBoundingClientRect();\n        this.w = r.width;\n        this.h = r.height;\n        this.canvas.width = this.w * this.dpr;\n        this.canvas.height = this.h * this.dpr;\n        this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);\n    };\n\n    // Grid: ~55 cols × ~35 rows. Pre-assign a color to each dot.\n    DataOcean.prototype._buildColors = function () {\n        var cols = Math.min(65, Math.ceil(this.w / 22) + 4);\n        var rows = 35;\n        this._cols = cols;\n        this._rows = rows;\n        var n = cols * rows;\n        this.colors = new Array(n);\n        var alt = this.opts.altRatio;\n        for (var i = 0; i < n; i++) {\n            this.colors[i] = Math.random() < alt ? this.opts.colorAlt : this.opts.color;\n        }\n    };\n\n    DataOcean.prototype._observe = function () {\n        var self = this;\n        if (\'IntersectionObserver\' in window) {\n            this._obs = new IntersectionObserver(function (e) {\n                self.visible = e[0].isIntersecting;\n            }, { rootMargin: \'150px 0px\' });\n            this._obs.observe(this.el);\n        } else {\n            this.visible = true;\n        }\n    };\n\n    DataOcean.prototype._loop = function () {\n        var self = this;\n        var last = 0;\n        (function tick(ts) {\n            self.raf = requestAnimationFrame(tick);\n            if (!self.visible) return;\n            if (ts - last < 30) return; // ~30 fps\n            last = ts;\n            self.time += 0.006;\n            self._draw(self.time);\n        })(0);\n    };\n\n    /**\n     * ── Core renderer ───────────────────────────────────────────────\n     *\n     * Approach: Think of a flat grid of dots on a table, viewed from a\n     * low angle. The table surface undulates with large rolling waves.\n     *\n     * "depth" goes from 0 (nearest / bottom of screen) to 1 (farthest /\n     * top area). Everything scales with depth:\n     *   - dot size shrinks\n     *   - dot opacity fades\n     *   - vertical row spacing compresses (perspective foreshortening)\n     *   - horizontal dot spacing tightens\n     *   - wave amplitude diminishes\n     *\n     * The wave function creates 2-3 visible rolling crests that sweep\n     * diagonally across the surface — matching the annual report cover.\n     */\n    DataOcean.prototype._draw = function (t) {\n        var ctx = this.ctx;\n        var w = this.w;\n        var h = this.h;\n        var opts = this.opts;\n        var cols = this._cols;\n        var rows = this._rows;\n\n        ctx.clearRect(0, 0, w, h);\n\n        // ── Perspective layout ──────────────────────────────────────\n        //\n        // The wave occupies the bottom ~55% of the section.\n        // "horizon" is where distant rows converge (top of wave area).\n        // "ground" is the bottom edge of the section.\n\n        var ground = h + 10;               // bottom edge (+ small overflow)\n        var horizon = h * 0.35;            // where distant dots vanish toward\n        var totalSpan = ground - horizon;   // vertical pixel range for the wave\n\n        var idx = 0;\n\n        // Draw back-to-front for correct visual layering\n        for (var row = rows - 1; row >= 0; row--) {\n\n            // ── Depth (0 = near/bottom, 1 = far/top) ───────────────\n            var depth = row / (rows - 1);\n\n            // Non-linear depth mapping: compress more toward horizon\n            // This creates the "accelerating compression" of perspective\n            var mappedDepth = Math.pow(depth, 0.55);\n\n            // Screen Y baseline for this row (no wave yet)\n            var baseY = ground - mappedDepth * totalSpan;\n\n            // ── Per-row properties (lerp by depth) ──────────────────\n            var dotR = lerp(opts.frontRadius, opts.backRadius, depth);\n            var dotA = lerp(opts.frontOpacity, opts.backOpacity, depth);\n            var colSpacing = lerp(w / (cols - 4), w / (cols + 15), depth);\n\n            // Slight horizontal offset per row (creates diagonal sweep)\n            var rowShift = depth * w * 0.12;\n\n            // ── Wave: two layers for organic rolling feel ───────────\n            //\n            // Primary wave: large rolling crests (creates the signature look)\n            // Secondary wave: smaller ripple for naturalism\n            //\n            // Wave amplitude is BIG near foreground and diminishes with depth.\n            // This is what makes the crests dramatically visible.\n\n            var waveScale = (1 - depth * 0.75); // waves diminish into distance\n            var amp1 = 70 * waveScale;           // primary crest amplitude (px)\n            var amp2 = 25 * waveScale;           // secondary ripple\n\n            for (var col = 0; col < cols; col++) {\n                // Screen X\n                var screenX = col * colSpacing - rowShift + colSpacing * 0.5;\n\n                // Wrap X for seamless edge handling\n                if (screenX < -30 || screenX > w + 30) { idx++; continue; }\n\n                // ── Wave displacement ───────────────────────────────\n                //\n                // The primary wave sweeps diagonally (uses both col and row).\n                // freq values tuned so ~2 full crests are visible across width.\n\n                var worldX = col * 24; // stable world-space coordinate for wave\n                var worldZ = row * 18;\n\n                var wave = amp1 * Math.sin(\n                    worldX * 0.0065 + worldZ * 0.012 + t * 0.9\n                );\n                wave += amp2 * Math.sin(\n                    worldX * 0.013 - worldZ * 0.008 + t * 0.55 + 1.8\n                );\n\n                var screenY = baseY - wave;\n\n                // Skip if outside visible area\n                if (screenY < -15 || screenY > h + 15) { idx++; continue; }\n\n                // ── Draw dot ────────────────────────────────────────\n                var c = this.colors[idx % this.colors.length];\n                ctx.beginPath();\n                ctx.arc(screenX, screenY, dotR, 0, PI2);\n                ctx.fillStyle = \'rgba(\' + c[0] + \',\' + c[1] + \',\' + c[2] + \',\' + dotA + \')\';\n                ctx.fill();\n\n                idx++;\n            }\n        }\n    };\n\n    DataOcean.prototype.destroy = function () {\n        if (this.raf) cancelAnimationFrame(this.raf);\n        if (this._obs) this._obs.disconnect();\n        if (this.canvas && this.canvas.parentNode) {\n            this.canvas.parentNode.removeChild(this.canvas);\n        }\n    };\n\n    // ── Auto-init ───────────────────────────────────────────────────\n    function init() {\n        var els = document.querySelectorAll(\'[data-particles]\');\n        var inst = [];\n        for (var i = 0; i < els.length; i++) inst.push(new DataOcean(els[i]));\n\n        window.DigiWinParticleOcean = {\n            instances: inst,\n            DataOcean: DataOcean,\n            refresh: function () {\n                for (var j = 0; j < inst.length; j++) inst[j].destroy();\n                inst = [];\n                var els2 = document.querySelectorAll(\'[data-particles]\');\n                for (var k = 0; k < els2.length; k++) inst.push(new DataOcean(els2[k]));\n                this.instances = inst;\n            }\n        };\n    }\n\n    if (document.readyState === \'loading\') {\n        document.addEventListener(\'DOMContentLoaded\', init);\n    } else {\n        init();\n    }\n})();\n</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ดูเศรษฐศาสตร์"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ดูเศรษฐศาสตร์: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ดูเศรษฐศาสตร์: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="bm-cta-section">\n    <div class="bm-cta-super-d" aria-hidden="true"></div>\n    \n    <div class="bm-cta-container">\n      <h2 class="bm-cta-title">ดูตัวเลขเศรษฐศาสตร์จริง</h2>\n      <p class="bm-cta-subtitle">คุณเห็นปัญหาแล้ว ตอนนี้มาดูตัวเลขของทางออก — สิ่งที่คุณเก็บได้ สิ่งที่เติบโตแบบทบต้น และทำไม 100% ของค่าบริการเป็นของคุณ</p>\n      <div class="bm-cta-btn-row">\n        <a href="/partner-program/economics/" class="bm-cta-btn bm-cta-btn--primary">ดูเศรษฐศาสตร์พาร์ทเนอร์</a>\n        <a href="/partner-program/solutions/" class="bm-cta-btn bm-cta-btn--ghost">ประเมินอาวุธก่อน</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100773;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100773 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100773, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === BUSINESS MODEL HERO (S1) === */\n.bm-hero-section{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%);padding:140px 24px 100px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.bm-hero-d-bg{position:absolute;right:-10%;top:-20%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center top;background-size:contain;opacity:0.14;pointer-events:none;z-index:0}\n.bm-hero-dot-overlay{position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:1}\n.bm-hero-inner{max-width:900px;margin:0 auto;position:relative;z-index:2}\n.bm-hero-breadcrumb{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-bottom:24px}\n.bm-hero-breadcrumb a{color:rgba(255,255,255,0.85);text-decoration:none;transition:color 0.2s}\n.bm-hero-breadcrumb a:hover{color:#00AFF0}\n.bm-hero-breadcrumb span{margin:0 8px}\n.bm-hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(36px,5vw,52px);font-weight:700;color:#fff;line-height:1.15;margin:0 0 24px;padding:0}\n.bm-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0;padding:0}\n@media(max-width:768px){\n  .bm-hero-section{padding:120px 20px 80px}\n  .bm-hero-title{font-size:32px}\n}\n/* === PATTERN CYCLE (S2) === */\n.pat-section{padding:100px 24px;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pat-inner{max-width:1000px;margin:0 auto;position:relative;z-index:2}\n.pat-header{text-align:center;margin:0 0 60px}\n.pat-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.pat-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.pat-cycle{display:grid;grid-template-columns:repeat(4,1fr);gap:24px;position:relative}\n.pat-cycle::before{content:\'\';position:absolute;top:48px;left:12.5%;right:12.5%;height:3px;background:linear-gradient(90deg,#dc2626,#f97316,#eab308,#dc2626);border-radius:2px;z-index:0}\n.pat-step{text-align:center;position:relative;z-index:1}\n.pat-icon{width:96px;height:96px;background:linear-gradient(135deg,#fef2f2 0%,#fee2e2 100%);border:2px solid #fecaca;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 24px}\n.pat-icon svg{width:40px;height:40px;stroke:#dc2626;fill:none}\n.pat-step h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 12px;padding:0}\n.pat-step p{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.pat-repeat{text-align:center;margin-top:48px;padding:32px;background:linear-gradient(135deg,#fef2f2,#fff5f5);border:1px solid #fecaca;border-radius:16px}\n.pat-repeat p{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:#991b1b;font-weight:500;margin:0;padding:0}\n.pat-repeat p svg{width:24px;height:24px;stroke:#dc2626;vertical-align:middle;margin-left:8px;fill:none}\n@media(max-width:1024px){\n  .pat-cycle{grid-template-columns:repeat(2,1fr);gap:48px}\n  .pat-cycle::before{display:none}\n}\n@media(max-width:768px){\n  .pat-section{padding:80px 20px}\n  .pat-cycle{grid-template-columns:1fr}\n  .pat-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.pat-step{transition:none !important}}\n/* === EVIDENCE CARDS (S3+S4) === */\n.math-section{padding:100px 24px;background:linear-gradient(180deg,#f8fafc 0%,#fff 100%);position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.math-section--row1{padding-bottom:0}\n.math-section--row2{background:#fff;padding-top:24px}\n.math-scene{position:absolute;inset:0;pointer-events:none;z-index:0}.math-scene svg{width:100%;height:100%;position:absolute;top:0;left:0;opacity:0.20}\n.math-wave-fade{position:relative;width:100%;height:120px;background-image:radial-gradient(circle at 50% 120%,rgba(0,175,240,0.06) 0%,transparent 60%);pointer-events:none;z-index:0;opacity:0.05;margin:-1px 0}\n.math-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.math-header{text-align:center;margin:0 0 60px}\n.math-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.math-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.math-cards{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.math-card{background:#fff;border:1px solid #fecaca;border-radius:20px;padding:40px;position:relative;overflow:hidden}\n.math-card::before{content:\'\';position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,#dc2626,#f97316)}\n.math-icon{width:64px;height:64px;background:linear-gradient(135deg,#dc2626,#b91c1c);border-radius:14px;display:flex;align-items:center;justify-content:center;margin-bottom:24px}\n.math-icon svg{width:32px;height:32px;stroke:#fff;fill:none}\n.math-card h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.math-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.7;margin:0 0 24px;padding:0}\n.math-formula{background:#fef2f2;border-radius:12px;padding:20px;text-align:center}\n.math-formula code{font-family:\'JetBrains Mono\',monospace;font-size:16px;font-weight:600;color:#991b1b}\n@media(max-width:1024px){\n  .math-cards{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .math-section{padding:80px 20px}\n  .math-section--row2{padding-top:20px}\n  .math-cards{grid-template-columns:1fr}\n  .math-header{margin-bottom:40px}\n}\n/* === THREE FUTURES (S5) === */\n.futures-section{padding:100px 24px;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.futures-wave-vertical{position:absolute;top:0;left:0;width:200px;height:100%;background:linear-gradient(90deg,rgba(0,175,240,0.04),transparent);pointer-events:none;z-index:0;opacity:0.06}\n.futures-insight-inner{max-width:900px;margin:0 auto;position:relative;z-index:2}\n.futures-header{text-align:center;margin:0 0 48px}\n.futures-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.futures-path-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.futures-paths{display:grid;gap:24px;margin-bottom:48px}\n.futures-path{border:1px solid;border-radius:16px;padding:32px}\n.futures-path-top{display:flex;align-items:center;gap:16px;margin-bottom:16px}\n.futures-path-icon{width:48px;height:48px;border-radius:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.futures-path h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;line-height:1.6;margin:0;padding:0}\n.futures-path-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:14px;margin:4px 0 0 0;padding:0}\n.futures-path-body{font-family:\'Noto Sans\',sans-serif;font-size:15px;line-height:1.7;margin:0;padding:0}\n.futures-insight{background:linear-gradient(135deg,#000864 0%,#000432 100%);border-radius:24px;padding:60px;text-align:center;position:relative;overflow:hidden}\n.futures-insight::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg width=\'40\' height=\'40\' viewBox=\'0 0 40 40\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Cpath d=\'M20 0l20 20-20 20L0 20z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none}\n.futures-insight-inner{position:relative;z-index:1}\n.futures-insight-quote{font-family:\'Noto Sans\',sans-serif;font-size:32px;font-weight:500;color:#fff;line-height:1.4;margin:0 0 32px;padding:0}\n.futures-insight-subtext{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.8);line-height:1.7;max-width:600px;margin:0 auto;padding:0}\n@media(max-width:768px){\n  .futures-section{padding:80px 20px}\n  .futures-insight{padding:40px 24px}\n  .futures-insight-quote{font-size:24px}\n  .futures-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.futures-path,.futures-insight{transition:none !important}}\n/* === SOLUTION CARDS (S6) === */\n.sol-section{padding:100px 24px;background:linear-gradient(180deg,#f8fafc 0%,#fff 100%);position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.sol-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.sol-header{text-align:center;margin:0 0 60px}\n.sol-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.sol-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.sol-cards{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.sol-card{background:#fff;border:1px solid #86efac;border-radius:20px;padding:40px;position:relative;overflow:hidden;transition:all 0.3s ease}\n.sol-card:hover{border-color:#00AFF0;box-shadow:0 12px 40px rgba(0,175,240,0.12)}\n.sol-card:hover .sol-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.sol-card::before{content:\'\';position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,#22c55e,#10b981)}\n.sol-icon{width:64px;height:64px;background:linear-gradient(135deg,#22c55e,#16a34a);border-radius:14px;display:flex;align-items:center;justify-content:center;margin-bottom:24px}\n.sol-icon svg{width:32px;height:32px;stroke:#fff;fill:none}\n.sol-card h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.sol-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.7;margin:0 0 24px;padding:0}\n.sol-formula{background:#f0fdf4;border-radius:12px;padding:20px;text-align:center}\n.sol-formula code{font-family:\'JetBrains Mono\',monospace;font-size:16px;font-weight:600;color:#166534}\n@media(max-width:1024px){\n  .sol-cards{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .sol-section{padding:80px 20px}\n  .sol-cards{grid-template-columns:1fr}\n  .sol-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.sol-card{transition:none !important}}\n/* === COMPARISON TABLE (S7) === */\n.cmp-section{padding:100px 24px;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.cmp-d-bg{position:absolute;bottom:0;right:0;width:400px;height:400px;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 200 200\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M100 0C44.8 0 0 44.8 0 100s44.8 100 100 100c55.2 0 100-44.8 100-100V0H100z\' fill=\'%23000864\' opacity=\'0.08\'/%3E%3C/svg%3E");background-size:contain;background-repeat:no-repeat;background-position:bottom right;pointer-events:none;z-index:0;opacity:0.08}\n.cmp-inner{max-width:1000px;margin:0 auto;position:relative;z-index:2}\n.cmp-header{text-align:center;margin-bottom:60px}\n.cmp-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.cmp-table{background:#fff;border-radius:20px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.08);width:100%;border-collapse:collapse}\n.cmp-table thead{background:#000864}\n.cmp-table th{padding:20px 24px;font-family:\'Noto Sans\',sans-serif;font-weight:600;font-size:16px;color:#fff;text-align:left}\n.cmp-table td{padding:20px 24px;font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#475569;border-bottom:1px solid #e2e8f0}\n.cmp-table tbody tr:last-child td{border-bottom:none}\n.cmp-table td:first-child{font-weight:600;color:#000864}\n.cmp-table td.bad{background:#fef2f2;color:#991b1b}\n.cmp-table td.good{background:#f0fdf4;color:#166534}\n.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0}\n@media(max-width:1024px){\n  .cmp-table thead{display:none}\n  .cmp-table tr{display:block;margin-bottom:16px;border:1px solid #e2e8f0;border-radius:12px;overflow:hidden}\n  .cmp-table td{display:flex;justify-content:space-between;align-items:center;gap:12px;text-align:right}\n  .cmp-table td::before{content:attr(data-label);font-family:\'Noto Sans\',sans-serif;font-weight:600;color:#000864;text-align:left;flex-shrink:0}\n  .cmp-table td:first-child{background:#000864;color:#fff;font-size:16px}\n  .cmp-table td:first-child::before{display:none}\n}\n@media(max-width:768px){\n  .cmp-section{padding:80px 20px}\n}\n/* === CTA: ดูเศรษฐศาสตร์ === */\n.bm-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.bm-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.bm-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.bm-cta-super-d{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.1;pointer-events:none;z-index:0}\n\n.bm-cta-container{position:relative;z-index:3;max-width:800px;margin:0 auto;text-align:center}\n.bm-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.bm-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.9);margin:0 0 40px;max-width:600px;margin-left:auto;margin-right:auto}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .bm-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .bm-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .bm-cta-container p{padding-bottom:0 !important}\n\n.bm-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.bm-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.bm-cta-btn:hover::before{left:100%}\n.bm-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.bm-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.bm-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.bm-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.bm-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.bm-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .bm-cta-title{font-size:28px;margin-bottom:16px}\n  .bm-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .bm-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .bm-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.bm-cta-btn{transition:none !important}.bm-cta-btn::before{display:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

